#include<bits/stdc++.h>
using namespace std;
vector<long long> prime;
bool isprime[10010];
long long f[10010];
int main()
{
    memset(isprime,1,sizeof(isprime));
    isprime[1]=0;
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=2;i<=n;i++)
    {
        if(!isprime[i])
        {
            continue;
        }
        prime.push_back(i);
        for(long long j=i*2;j<=n;j+=i)
        {
            isprime[j]=0;
        }
    }
    f[0]=1;
    for(long long i:prime)
    {
        for(long long j=n;j>=i;j--)
        {
            long long tmp=i;
            while(tmp<=j)
            {
                f[j]+=f[j-tmp]*tmp%m;
                f[j]%=m;
                tmp*=i;
            }
        }
    }
    long long ans=0;
    for(long long i=0;i<=n;i++)
    {
        ans+=f[i];
        ans%=m;
    }
    printf("%lld",ans);
    return 0;
}
